class ReadingProgress extends HTMLElement{constructor(){super();this.attachShadow({mode: 'open'});this._ticking=false;}static get observedAttributes(){return ['color','height','position'];}connectedCallback(){this.render();this.setupScrollListener();}disconnectedCallback(){this.removeEventListeners();}attributeChangedCallback(){if(this.shadowRoot){this.render();}}render(){const color=this.getAttribute('color')||'var(--md-sys-color-primary,#0061AB)';const height=this.getAttribute('height')||'4';const position=this.getAttribute('position')||'top';this.shadowRoot.innerHTML=`<style>:host{position: fixed;${position}: 0;left: 0;width: 100%;height: ${height}px;z-index: 10000;background: transparent;}.progress-bar{height: 100%;width: 0%;background: ${color};transition: width 0.1s ease-out;}.progress-bar.gradient{background: linear-gradient(90deg,var(--md-sys-color-primary,#0061AB)0%,var(--md-sys-color-secondary,#006E1C)50%,var(--md-sys-color-tertiary,#7E48D7)100%);}@media(prefers-reduced-motion: reduce){.progress-bar{transition: none;}}</style><div class="progress-bar" role="progressbar" aria-label="Tiến độ đọc"></div>`;}setupScrollListener(){this._onScroll=()=>{if(!this._ticking){window.requestAnimationFrame(()=>{this.updateProgress();this._ticking=false;});this._ticking=true;}};window.addEventListener('scroll',this._onScroll,{passive: true});this.updateProgress();}updateProgress(){const doc=document.documentElement;const scrollTop=window.scrollY||0;const docHeight=doc.scrollHeight-doc.clientHeight;const scrollPercent=docHeight>0 ?(scrollTop/docHeight)*100 : 0;const progressBar=this.shadowRoot.querySelector('.progress-bar');if(progressBar){progressBar.style.width=`${scrollPercent}%`;progressBar.setAttribute('aria-valuenow',Math.round(scrollPercent));}}removeEventListeners(){window.removeEventListener('scroll',this._onScroll);}reset(){const progressBar=this.shadowRoot.querySelector('.progress-bar');if(progressBar){progressBar.style.width='0%';}}}if(!customElements.get('reading-progress')){customElements.define('reading-progress',ReadingProgress);}export{ReadingProgress};